// MARK: - Constants

struct AppConstants {
    static let BASE_API_URL = "https://api.example.com/"
}

// MARK: - Networking

enum NetworkError: Error {
    case invalidURL
    case noData
    case decodingError
}

class APIController {
    func executeRequest(urlString: String, parameters: [String : Any], completion: @escaping ([String : Any]?, Error?) -> Void) {
        guard let url = URL(string: urlString + AppConstants.BASE_API_URL),
              var request = URLRequest(url: url, cachePolicy: .useProtocolVersion)
        else {
            completion(nil, NetworkError.invalidURL)
            return
        }
        
        request.httpMethod = "GET"
        request.httpBody = try? JSONSerialization.data(withJSONObject: parameters)

        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(nil, error)
                return
            }

            guard let data = data,
                  let json = try? JSONSerialization.jsonObject(with: data, options: []) as? [String : Any]
            else {
                completion(nil, NetworkError.noData)
                return
            }
            
            completion(json, nil)
        }.resume()
    }
}

