// MARK: - Secure API Communication

class KeychainService {
    class func save(value: String, forKey key: String) -> Bool {
        let SecAttrAccessible = kSecAttrAccessibleWhenUnlockedThisDeviceOnly.rawValue
        let attributes: [String : Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: value.data(using: .utf8)!,
            kSecAttrAccessible as String: SecAttrAccessible
        ]

        let status = SecItemDelete((kSecClassGenericPassword as NSString).addingAttributeEncoding(kSecAttrAccount as String, value: key)) as OSStatus

        if status == errSecSuccess {
            return SecItemAdd(attributes, nil) == noErr
        } else if status == errSecDuplicateItem {
            let fetchRequest = [kSecClass as String : kSecClassGenericPassword,
                                kSecAttrAccount as String : key] as [String : Any]
            _ = SecItemUpdate(fetchRequest, attributes)
            return true
        }

        return false
    }

    class func retrieve(forKey key: String) -> String? {
        let fetchRequest = [kSecClass as String : kSecClassGenericPassword,
                            kSecAttrAccount as String : key] as [String : Any]

        var value: AnyObject?
        SecItemCopyMatching(fetchRequest, nil, &value)

        return (value as? Data)?.string(encoding: .utf8)
    }
}